// Build customer activity index, classify each into a segment
const customers = $('Square: All Customers').first().json.customers || [];
const bookings = $('Square: Past Bookings').first().json.bookings || [];

const byCustomer = {};
for (const b of bookings) {
  const id = b.customer_id;
  if (!id) continue;
  if (!byCustomer[id]) byCustomer[id] = [];
  byCustomer[id].push(b);
}

const now = new Date();
const monthIdx = now.getMonth() + 1; // 1-12
const inSeason = monthIdx >= 4 && monthIdx <= 8;
const today = now.toISOString().slice(0,10);
const monthDay = `${String(monthIdx).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;

const output = [];
for (const c of customers) {
  const tags = (c.note || '').match(/tag:[a-z_]+/g) || [];
  if (tags.includes('tag:do_not_engage') || tags.includes('tag:discount_seeker') || tags.includes('tag:complainer')) continue;
  const cb = (byCustomer[c.id] || []).sort((a, b) => new Date(b.start_at) - new Date(a.start_at));
  if (cb.length === 0) continue;
  const last = cb[0];
  const lastDate = new Date(last.start_at);
  const daysSince = Math.floor((now - lastDate) / 86400000);
  const lifetimeServices = cb.length;

  let segment = null;
  // Date-anchored segments
  if (monthDay === '03-15' || monthDay === '04-01') segment = 'pre_season';
  else if (monthDay === '08-01') segment = 'eos_ceramic';
  else if (monthDay === '04-15' && daysSince > 120) segment = 'salt_recovery';
  // Day-since-last segments (in-season only for routine nudges)
  else if (inSeason && daysSince >= 85 && daysSince <= 95) segment = '90_day';
  else if (inSeason && daysSince >= 175 && daysSince <= 185) segment = '180_day';
  else if (inSeason && daysSince >= 360 && daysSince <= 370) segment = '365_day';
  // Plan upsells (only fire monthly to avoid spam — gate by day == 5)
  else if (now.getDate() === 5 && lifetimeServices >= 3 && !tags.includes('tag:on_plan')) segment = 'maintenance_upsell';
  else if (now.getDate() === 12 && tags.includes('tag:multi_vehicle') && !tags.includes('tag:family_plan')) segment = 'family_upsell';

  if (!segment) continue;
  output.push({
    json: {
      customer_id: c.id,
      first_name: c.given_name || '',
      phone_e164: c.phone_number || '',
      vehicle: (c.note || '').match(/vehicle:[^|]+/)?.[0]?.replace('vehicle:', '').trim() || 'your vehicle',
      last_service_type: last.appointment_segments?.[0]?.service_variation_id || 'detail',
      last_service_date: lastDate.toISOString().slice(0,10),
      days_since: daysSince,
      lifetime_services: lifetimeServices,
      tags,
      segment
    }
  });
}

return output;

const raw = $input.first().json.output || $input.first().json.text || '';
const match = raw.match(/\{[\s\S]*\}/);
if (!match) throw new Error('AI did not return JSON');
const parsed = JSON.parse(match[0]);
if (parsed.skip) {
  // Drop skipped customers
  return [];
}
// Compute scheduled send time — clamp to 9am-8pm
let scheduled = parsed.scheduled_send_iso ? new Date(parsed.scheduled_send_iso) : new Date();
const hour = scheduled.getHours();
if (hour < 9) scheduled.setHours(9, 0, 0, 0);
if (hour >= 20) {
  scheduled.setDate(scheduled.getDate() + 1);
  scheduled.setHours(9, 0, 0, 0);
}
return (parsed.messages || []).map((body, i) => ({
  json: {
    customer_id: parsed.customer_id,
    segment: parsed.segment,
    send_via: parsed.send_via || 'sms',
    to: $('Classify into Segment').itemMatching($itemIndex).json.phone_e164,
    body,
    scheduled_iso: scheduled.toISOString(),
    delay_ms: i * 1500
  }
}));

// Pick 3 targets that haven't been pitched in 8+ weeks (or ever)
const data = JSON.parse($input.first().json.data?.toString() || '{"targets":[]}');
const now = new Date();
const eightWeeksAgo = now.getTime() - (8 * 7 * 86400000);

const eligible = (data.targets || []).filter(t => {
  if (t.do_not_pitch) return false;
  if (!t.last_pitched) return true;
  return new Date(t.last_pitched).getTime() < eightWeeksAgo;
});

// Sort by oldest pitch first (or never-pitched bubble up)
eligible.sort((a, b) => {
  if (!a.last_pitched && !b.last_pitched) return 0;
  if (!a.last_pitched) return -1;
  if (!b.last_pitched) return 1;
  return new Date(a.last_pitched) - new Date(b.last_pitched);
});

const picks = eligible.slice(0, 3);
if (picks.length === 0) return [{ json: { body: 'fleet pitch list: no eligible targets this week. add new ones to data/fleet-targets.json' } }];

const lines = picks.map((t, i) => `${i+1}. *${t.name}* (${t.city}) — ${t.angle}\n   contact: ${t.contact}`).join('\n');
return [{
  json: {
    body: `:briefcase: *Fleet pitch list — week of ${now.toISOString().slice(0,10)}*\n\n${lines}\n\n_walk these in this week. update \`data/fleet-targets.json\` after each pitch with the date + status._`
  }
}];
